import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── Fetch Vault History ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data?.data || res.data || []);
    } catch {
      toast.error('VAULT_SYNC_ERROR: UNABLE_TO_REACH_DATABASE');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── Delete Strategy ───────── */
  const handleDelete = async (id) => {
    if (!window.confirm('This strategy will be permanently deleted. Continue?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('DATA_PURGE_SUCCESSFUL');
    } catch {
      toast.error('WIPE_FAILURE: DATA_PROTECTED_BY_SYSTEM');
    }
  };

  /* ───────── Export PDF ───────── */
  const handleDownload = async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, {
        responseType: 'blob'
      });

      const blob = new Blob([res.data], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `Finify_Strategy_${item.id}.pdf`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('EXPORT_FAILED: GENERATION_ERROR');
    }
  };

  /* ───────── Lock Scroll When Modal Open ───────── */
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) {
    return <div style={centerStyle}>SYNCHRONIZING_STRATEGY_VAULT...</div>;
  }

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* Header */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={40} /> STRATEGY_VAULT
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={20} /> {history.length} ACTIVE_NODES
        </div>
      </div>

      {/* List */}
      <div style={listStyle}>
        {history.length === 0 && (
          <div style={emptyState}>
            NO_DATA_FOUND: INITIALIZE_STRATEGY_IN_DASHBOARD
          </div>
        )}

        {history.map(item => (
          <div key={item.id} style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '30px' }}>
                <span style={dateTag}>
                  <Calendar size={18} />
                  {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={riskTag}>
                  <ShieldCheck size={18} />
                  RISK_EXPOSURE: {item.risk_score}
                </span>
              </div>

              <div style={cardActions}>
                <button style={iconBtn} onClick={() => setSelectedItem(item)}>
                  <Eye size={28} />
                </button>
                <button style={iconBtn} onClick={() => handleDownload(item)}>
                  <Download size={28} />
                </button>
                <button style={deleteBtn} onClick={() => handleDelete(item.id)}>
                  <Trash2 size={28} />
                </button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            <div style={sectionBlock}>
              <p style={labelSmall}>
                <AlignLeft size={14} /> STRATEGIC_SUMMARY
              </p>
              <ReactMarkdown>{item.summary}</ReactMarkdown>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader(isDark)}>
              <span style={modalId}>
                NODE_DATA // SYNC_ID_{selectedItem.id}
              </span>
              <button style={closeBtn(isDark)} onClick={() => setSelectedItem(null)}>
                <X size={32} />
              </button>
            </div>

            <div style={modalBody(isDark)}>
              <h3 style={modalTitle(isDark)}>{selectedItem.goal}</h3>
              <p style={modalLabel}>
                <AlignLeft size={18} /> AGENTIC_RATIONALE
              </p>
              <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ───────── Styles ───────── */

const containerStyle = { padding: '5rem 2rem', maxWidth: '1400px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '5rem' };
const headerStyle = { display: 'flex', alignItems: 'center', gap: '20px', fontSize: '2.8rem', fontWeight: 900 };
const vaultBadge = { display: 'flex', gap: '10px', fontWeight: 900 };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '4rem' };
const cardStyle = { padding: '4rem', borderRadius: '36px', border: '2px solid var(--surface-border)' };
const cardMeta = { display: 'flex', justifyContent: 'space-between', marginBottom: '2.5rem' };
const dateTag = { display: 'flex', gap: '10px', fontWeight: 700 };
const riskTag = { display: 'flex', gap: '10px', fontWeight: 900 };
const cardActions = { display: 'flex', gap: '20px' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };
const titleStyle = { fontSize: '2.2rem', fontWeight: 900, marginBottom: '2rem' };
const labelSmall = { fontSize: '0.9rem', fontWeight: 900, letterSpacing: '0.2em', display: 'flex', gap: '10px' };
const sectionBlock = {};
const emptyState = { textAlign: 'center', opacity: 0.6 };
const centerStyle = { height: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center' };

const modalOverlay = isDark => ({
  position: 'fixed',
  inset: 0,
  background: isDark ? 'rgba(0,0,0,0.95)' : 'rgba(255,255,255,0.9)',
  display: 'flex',
  justifyContent: 'center',
  alignItems: 'center'
});

const modalContent = isDark => ({
  width: '90%',
  maxWidth: '1200px',
  background: isDark ? '#000' : '#fff',
  borderRadius: '32px'
});

const modalHeader = () => ({
  padding: '2rem',
  display: 'flex',
  justifyContent: 'space-between'
});

const modalId = { fontFamily: 'monospace', fontWeight: 900 };
const modalBody = () => ({ padding: '3rem', maxHeight: '75vh', overflowY: 'auto' });
const modalTitle = () => ({ fontSize: '2.8rem', fontWeight: 900 });
const modalLabel = { fontWeight: 900, marginBottom: '1.5rem', display: 'flex', gap: '10px' };
const closeBtn = () => ({ background: 'none', border: 'none', cursor: 'pointer' });

export default VaultPage;
